@Repository
class ElasticsearchRepositorySupport {

    private final RestHighLevelClient client;

    public ElasticsearchRepositorySupport(RestHighLevelClient client) {
        this.client = client;
    }

    public void index(String index, String id, String json) throws IOException {
        IndexRequest request = new IndexRequest(index).id(id).source(json, XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    public void bulkIndex(String index, List<Map<String, Object>> docs) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        for (Map<String, Object> doc : docs) {
            String id = String.valueOf(doc.get("id"));
            bulkRequest.add(new IndexRequest(index).id(id).source(doc));
        }
        client.bulk(bulkRequest, RequestOptions.DEFAULT);
    }

    public SearchResponse search(SearchRequest request) throws IOException {
        return client.search(request, RequestOptions.DEFAULT);
    }

    public RestHighLevelClient getClient() {
        return client;
    }
}

@Service
class IndexManagementService {

    public static final String PRODUCT_INDEX = "products";
    public static final String SEARCH_LOG_INDEX = "search_queries";

    private final RestHighLevelClient client;

    public IndexManagementService(RestHighLevelClient client) {
        this.client = client;
    }

    public void initialize() throws IOException {
        createProductIndexIfMissing();
        createSearchLogIndexIfMissing();
    }

    private void createProductIndexIfMissing() throws IOException {
        if (!client.indices().exists(new GetIndexRequest(PRODUCT_INDEX), RequestOptions.DEFAULT)) {
            CreateIndexRequest request = new CreateIndexRequest(PRODUCT_INDEX);
            request.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 1)
                    .put("analysis.analyzer.folded.type", "custom")
                    .put("analysis.analyzer.folded.tokenizer", "standard")
                    .putList("analysis.analyzer.folded.filter", "lowercase", "asciifolding"));
            request.mapping("{\n" +
                    "  \"properties\": {\n" +
                    "    \"sku\": {\"type\": \"keyword\"},\n" +
                    "    \"name\": {\"type\": \"text\", \"analyzer\": \"folded\", \"fields\": {\"keyword\": {\"type\": \"keyword\"}}},\n" +
                    "    \"description\": {\"type\": \"text\", \"analyzer\": \"folded\"},\n" +
                    "    \"brand\": {\"type\": \"keyword\"},\n" +
                    "    \"category\": {\"type\": \"keyword\"},\n" +
                    "    \"tags\": {\"type\": \"keyword\"},\n" +
                    "    \"price\": {\"type\": \"double\"},\n" +
                    "    \"currency\": {\"type\": \"keyword\"},\n" +
                    "    \"stock\": {\"type\": \"integer\"},\n" +
                    "    \"rating\": {\"type\": \"double\"},\n" +
                    "    \"active\": {\"type\": \"boolean\"},\n" +
                    "    \"createdAt\": {\"type\": \"date\"}\n" +
                    "  }\n" +
                    "}", XContentType.JSON);
            client.indices().create(request, RequestOptions.DEFAULT);
        }
    }

    private void createSearchLogIndexIfMissing() throws IOException {
        if (!client.indices().exists(new GetIndexRequest(SEARCH_LOG_INDEX), RequestOptions.DEFAULT)) {
            CreateIndexRequest request = new CreateIndexRequest(SEARCH_LOG_INDEX);
            request.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 1));
            request.mapping("{\n" +
                    "  \"properties\": {\n" +
                    "    \"query\": {\"type\": \"text\"},\n" +
                    "    \"category\": {\"type\": \"keyword\"},\n" +
                    "    \"brand\": {\"type\": \"keyword\"},\n" +
                    "    \"minPrice\": {\"type\": \"double\"},\n" +
                    "    \"maxPrice\": {\"type\": \"double\"},\n" +
                    "    \"resultCount\": {\"type\": \"integer\"},\n" +
                    "    \"searchedAt\": {\"type\": \"date\"},\n" +
                    "    \"sessionId\": {\"type\": \"keyword\"},\n" +
                    "    \"customerId\": {\"type\": \"keyword\"}\n" +
                    "  }\n" +
                    "}", XContentType.JSON);
            client.indices().create(request, RequestOptions.DEFAULT);
        }
    }

    public void recreateProductIndex() throws IOException {
        if (client.indices().exists(new GetIndexRequest(PRODUCT_INDEX), RequestOptions.DEFAULT)) {
            client.indices().delete(new DeleteIndexRequest(PRODUCT_INDEX), RequestOptions.DEFAULT);
        }
        createProductIndexIfMissing();
    }
}

@Service
class ProductIndexService {

    private final ElasticsearchRepositorySupport repositorySupport;

    public ProductIndexService(ElasticsearchRepositorySupport repositorySupport) {
        this.repositorySupport = repositorySupport;
    }

    public void indexProduct(Product product) throws IOException {
        repositorySupport.index(IndexManagementService.PRODUCT_INDEX, product.getId(), JsonUtil.toJson(product));
    }

    public void bulkIndexProducts(List<Product> products) throws IOException {
        List<Map<String, Object>> docs = products.stream().map(JsonUtil::toMap).collect(Collectors.toList());
        repositorySupport.bulkIndex(IndexManagementService.PRODUCT_INDEX, docs);
    }
}

