@Service
class ProductSearchService {

    private final ElasticsearchRepositorySupport repositorySupport;
    private final SearchLogService searchLogService;

    public ProductSearchService(ElasticsearchRepositorySupport repositorySupport, SearchLogService searchLogService) {
        this.repositorySupport = repositorySupport;
        this.searchLogService = searchLogService;
    }

    public ProductSearchResponse search(ProductSearchRequest request) throws IOException {
        SearchRequest searchRequest = new SearchRequest(IndexManagementService.PRODUCT_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery()
                .filter(QueryBuilders.termQuery("active", true));

        if (request.getQuery() != null && !request.getQuery().isBlank()) {
            MultiMatchQueryBuilder multiMatch = QueryBuilders.multiMatchQuery(request.getQuery(), "name^4", "description^2", "brand^2", "category", "tags")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness(Fuzziness.AUTO);
            boolQuery.must(multiMatch);
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (request.getCategory() != null && !request.getCategory().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("category", request.getCategory()));
        }

        if (request.getBrand() != null && !request.getBrand().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("brand", request.getBrand()));
        }

        if (request.getTags() != null && !request.getTags().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("tags", request.getTags()));
        }

        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (request.getMinPrice() != null) {
                rangeQuery.gte(request.getMinPrice().doubleValue());
            }
            if (request.getMaxPrice() != null) {
                rangeQuery.lte(request.getMaxPrice().doubleValue());
            }
            boolQuery.filter(rangeQuery);
        }

        sourceBuilder.query(boolQuery);
        sourceBuilder.from(request.getPage() * request.getSize());
        sourceBuilder.size(request.getSize());

        if (!"_score".equalsIgnoreCase(request.getSortBy())) {
            sourceBuilder.sort(request.getSortBy(), "asc".equalsIgnoreCase(request.getSortOrder())
                    ? org.elasticsearch.search.sort.SortOrder.ASC
                    : org.elasticsearch.search.sort.SortOrder.DESC);
        }

        HighlightBuilder highlightBuilder = new HighlightBuilder()
                .field("name")
                .field("description")
                .preTags("<em>")
                .postTags("</em>");
        sourceBuilder.highlighter(highlightBuilder);

        sourceBuilder.aggregation(AggregationBuilders.terms("brandFacet").field("brand").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("categoryFacet").field("category").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("tagFacet").field("tags").size(20));

        searchRequest.source(sourceBuilder);

        SearchResponse response = repositorySupport.search(searchRequest);

        ProductSearchResponse result = new ProductSearchResponse();
        result.setTotal(response.getHits().getTotalHits() != null ? response.getHits().getTotalHits().value : 0L);

        List<ProductSearchHit> hits = Arrays.stream(response.getHits().getHits()).map(hit -> {
            Map<String, Object> src = hit.getSourceAsMap();
            ProductSearchHit item = new ProductSearchHit();
            item.setId(hit.getId());
            item.setSku((String) src.get("sku"));
            item.setName((String) src.get("name"));
            item.setDescription((String) src.get("description"));
            item.setBrand((String) src.get("brand"));
            item.setCategory((String) src.get("category"));
            Object tags = src.get("tags");
            if (tags instanceof List) {
                item.setTags(((List<?>) tags).stream().map(String::valueOf).collect(Collectors.toList()));
            }
            Object price = src.get("price");
            if (price != null) {
                item.setPrice(new BigDecimal(String.valueOf(price)));
            }
            item.setCurrency((String) src.get("currency"));
            Object stock = src.get("stock");
            if (stock != null) {
                item.setStock(Integer.valueOf(String.valueOf(stock)));
            }
            Object rating = src.get("rating");
            if (rating != null) {
                item.setRating(Double.valueOf(String.valueOf(rating)));
            }
            item.setScore(hit.getScore());
            if (hit.getHighlightFields() != null && !hit.getHighlightFields().isEmpty()) {
                Map<String, List<String>> hl = new HashMap<>();
                hit.getHighlightFields().forEach((k, v) -> hl.put(k, Arrays.stream(v.fragments()).map(Object::toString).collect(Collectors.toList())));
                item.setHighlights(hl);
            }
            return item;
        }).collect(Collectors.toList());

        result.setProducts(hits);

        Map<String, List<FacetBucket>> facets = new HashMap<>();
        ParsedStringTerms brandFacet = response.getAggregations().get("brandFacet");
        ParsedStringTerms categoryFacet = response.getAggregations().get("categoryFacet");
        ParsedStringTerms tagFacet = response.getAggregations().get("tagFacet");

        facets.put("brand", brandFacet.getBuckets().stream().map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount())).collect(Collectors.toList()));
        facets.put("category", categoryFacet.getBuckets().stream().map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount())).collect(Collectors.toList()));
        facets.put("tags", tagFacet.getBuckets().stream().map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount())).collect(Collectors.toList()));
        result.setFacets(facets);

        searchLogService.log(request, (int) result.getTotal());

        return result;
    }
}

@RestController
@RequestMapping("/api/products")
class ProductController {

    private final ProductIndexService productIndexService;
    private final ProductSearchService productSearchService;

    public ProductController(ProductIndexService productIndexService, ProductSearchService productSearchService) {
        this.productIndexService = productIndexService;
        this.productSearchService = productSearchService;
    }

    @PostMapping
    public ResponseEntity<?> indexProduct(@RequestBody Product product) {
        try {
            if (product.getId() == null || product.getId().isBlank()) {
                product.setId(UUID.randomUUID().toString());
            }
            if (product.getCreatedAt() == null) {
                product.setCreatedAt(Instant.now());
            }
            if (product.getActive() == null) {
                product.setActive(true);
            }
            productIndexService.indexProduct(product);
            return ResponseEntity.status(HttpStatus.CREATED).body(Map.of("id", product.getId(), "status", "indexed"));
        } catch (IOException e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(Map.of("error", e.getMessage()));
        }
    }

    @PostMapping("/bulk")
    public ResponseEntity<?> bulkIndex(@RequestBody List<Product> products) {
        try {
            for (Product product : products) {
                if (product.getId() == null || product.getId().isBlank()) {
                    product.setId(UUID.randomUUID().toString());
                }
                if (product.getCreatedAt() == null) {
                    product.setCreatedAt(Instant.now());
                }
                if (product.getActive() == null) {
                    product.setActive(true);
                }
            }
            productIndexService.bulkIndexProducts(products);
            return ResponseEntity.status(HttpStatus.CREATED).body(Map.of("count", products.size(), "status", "indexed"));
        } catch (IOException e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(Map.of("error", e.getMessage()));
        }
    }

    @PostMapping("/search")
    public ResponseEntity<?> search(@RequestBody ProductSearchRequest request) {
        try {
            return ResponseEntity.ok(productSearchService.search(request));
        } catch (IOException e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(Map.of("error", e.getMessage()));
        }
    }
}

class JsonUtil {
    private static final com.fasterxml.jackson.databind.ObjectMapper MAPPER = new com.fasterxml.jackson.databind.ObjectMapper()
            .findAndRegisterModules();

    public static String toJson(Object object) {
        try {
            return MAPPER.writeValueAsString(object);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @SuppressWarnings("unchecked")
    public static Map<String, Object> toMap(Object object) {
        return MAPPER.convertValue(object, Map.class);
    }
}